#!/usr/bin/env node
// AUTOGENERATED-DRIVER — generates lighthouserc.json + lychee.toml from
// build.config.json + scripts/fixtures/lhci-assertions.json.
//
// The workflow-YAML generator (build-artifacts spec Phase 4: mutate
// `.github/workflows/*.yml` artifact upload paths via yaml@2.5.x Document
// API with stable `name:` selectors) is deferred — workflows are
// hand-edited today; their `path:` values reference `.build/...` directly.
// See docs/build-artifacts.md line 65 for the deferral context.
//
// See openspec/specs/build-config/spec.md (originally authored in the
// archived openspec/changes/archive/2026-05-05-standardize-build-artifacts/
// proposal — its `build-config` capability is now the live spec).

import { createHash } from "node:crypto";
import {
  existsSync,
  readFileSync,
  statSync,
  writeFileSync,
  mkdirSync,
} from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { argv, env, exit, hrtime } from "node:process";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, "..");
const CONFIG_PATH = join(ROOT, "build.config.json");
const FIXTURE_PATH = join(ROOT, "scripts/fixtures/lhci-assertions.json");

// CI auto-promotes to --check: sync MUST NOT write generated files in CI;
// any drift is the contributor's responsibility to commit locally. CI's
// drift gate fails the build on non-empty diff.
const CI = env.GITHUB_ACTIONS === "true";
const CHECK_MODE = argv.includes("--check") || CI;
const SKIP = env.SKIP_BUILD_SYNC === "1";

if (SKIP) {
  console.log("sync:build-config skipped (SKIP_BUILD_SYNC=1)");
  exit(0);
}

// ---------- Path validation ----------
const PATH_REGEX = /^\.build\/[a-z0-9/_-]+$/;
function validatePaths(obj, prefix = "") {
  for (const [k, v] of Object.entries(obj)) {
    const path = prefix ? `${prefix}.${k}` : k;
    if (typeof v === "string") {
      if (k === "root") {
        if (v !== ".build") fail(`build.config.json: ${path} must be ".build"`);
        continue;
      }
      if (!PATH_REGEX.test(v)) {
        fail(
          `build.config.json: invalid path string at ${path}: ${JSON.stringify(v)} (must match ${PATH_REGEX})`,
        );
      }
      if (/\.\.|\n|`|\$\(|^\//.test(v)) {
        fail(
          `build.config.json: rejected suspicious path at ${path}: ${JSON.stringify(v)}`,
        );
      }
    } else if (v && typeof v === "object") {
      validatePaths(v, path);
    }
  }
}

function fail(msg) {
  console.error(`✗ ${msg}`);
  exit(1);
}

// ---------- Inputs ----------
const buildConfig = JSON.parse(readFileSync(CONFIG_PATH, "utf8"));
validatePaths(buildConfig);

const configSha = createHash("sha256")
  .update(readFileSync(CONFIG_PATH))
  .digest("hex")
  .slice(0, 16);

// ---------- Fast-path mtime check ----------
const inputs = [CONFIG_PATH];
if (existsSync(FIXTURE_PATH)) inputs.push(FIXTURE_PATH);
const outputs = [join(ROOT, "lighthouserc.json"), join(ROOT, "lychee.toml")];
const start = hrtime.bigint();
const allOutputsExist = outputs.every((p) => existsSync(p));
if (allOutputsExist && !CHECK_MODE) {
  const inputMaxMtime = Math.max(...inputs.map((p) => statSync(p).mtimeMs));
  const outputMinMtime = Math.min(...outputs.map((p) => statSync(p).mtimeMs));
  if (inputMaxMtime <= outputMinMtime) {
    const elapsedMs = Number(hrtime.bigint() - start) / 1e6;
    if (elapsedMs > 50) {
      console.warn(
        `# slow-fastpath: mtime check took ${elapsedMs.toFixed(1)}ms`,
      );
    }
    exit(0);
  }
}

// CI write-block has been replaced by CHECK_MODE auto-promotion above.
// In CI, sync runs in check-only mode: any required regeneration becomes
// a non-zero exit (drift gate). Local writes stay enabled.

// ---------- Generators ----------
function emitJson(targetPath, obj) {
  const banner = { $generated: "build.config.json", $sha: configSha };
  const merged = { ...banner, ...obj };
  const body = JSON.stringify(merged, null, 2) + "\n";
  return writeIfChanged(targetPath, body);
}

function emitToml(targetPath, body) {
  const banner =
    `# AUTOGENERATED — do not edit. Source: build.config.json (sha=${configSha}). ` +
    `Run: npm run sync:build-config\n`;
  return writeIfChanged(targetPath, banner + body);
}

function writeIfChanged(targetPath, content) {
  if (existsSync(targetPath)) {
    const current = readFileSync(targetPath, "utf8");
    if (current === content) return { path: targetPath, changed: false };
  }
  if (CHECK_MODE) {
    return { path: targetPath, changed: true, wouldWrite: true };
  }
  mkdirSync(dirname(targetPath), { recursive: true });
  writeFileSync(targetPath, content);
  return { path: targetPath, changed: true };
}

// ---------- lighthouserc.json ----------
// Strip $comment* keys recursively from fixture data before merging into
// generated output. The fixture uses comment sentinels for human readers;
// LHCI tolerates them but they pollute the generated artifact.
function stripComments(value) {
  if (Array.isArray(value)) return value.map(stripComments);
  if (value && typeof value === "object") {
    return Object.fromEntries(
      Object.entries(value)
        .filter(([k]) => !k.startsWith("$comment"))
        .map(([k, v]) => [k, stripComments(v)]),
    );
  }
  return value;
}

let lhciAssertions = {};
if (existsSync(FIXTURE_PATH)) {
  lhciAssertions = stripComments(
    JSON.parse(readFileSync(FIXTURE_PATH, "utf8")),
  );
}
const lhci = {
  ci: {
    collect: {
      staticDistDir: buildConfig.dist,
      // LHCI auto-prepends its internal server's host:port to relative URLs.
      // The fixture supplies path-only entries (e.g. "/platform/") so the
      // generated rc doesn't bake in a host that may collide with the runner.
      url: lhciAssertions.urls ?? ["/"],
    },
    assert: lhciAssertions.assert ?? {},
    upload: {
      target: "filesystem",
      outputDir: buildConfig.reports.lhci,
    },
  },
};

// ---------- lychee.toml ----------
// NOTE: lychee v0.23 dropped `cache_path` as a config key; caching is enabled
// via `cache = true`. The cache directory is controlled by --cache-dir CLI
// flag (lychee defaults to `.lycheecache/` at repo root if not specified).
//
// `.github/workflows/link-check.yml` passes
// `--cache-dir .build/cache/lychee` so the cache lives under the .build
// umbrella. `.gitignore` also lists `.lycheecache/` as defense-in-depth in
// case a future workflow change drops the flag.
const lycheeBody = `cache = true
exclude_path = [
  "${buildConfig.dist}",
  "node_modules",
  "${buildConfig.root}",
  # Skill source files contain template placeholders (\$s, \$variable) and
  # blog-style root-relative paths (/posts/...) that aren't real links —
  # they're documentation snippets meant to be copy-edited by skill
  # consumers. Lychee can't distinguish doc-template from real href.
  ".agents/skills",
  ".claude/skills",
]
timeout = 30
# Retry HTTP requests on network errors (e.g. astro.build connection-resets
# from GitHub-hosted runners). Total attempts = 1 + max_retries; with 5s
# backoff, three retries cap each URL at ~16s before lychee gives up.
retry_wait_time = 5
max_retries = 3
accept = [200, 204, 206, 301, 302, 304, 307, 308, 403, 429]
include_verbatim = true
no_progress = true
# Resolve root-relative links (e.g. \`/writing/feed.xml\` cited in the
# USMR rolling narrative) against the repo root instead of erroring
# with "Cannot resolve root-relative link". Resolution turns each into
# a file:// URL pointing at <repo>/<path>; non-existent ones become
# normal file-not-found errors that the file:// exclude patterns
# can match. (Lychee 0.24+ renamed \`base\` → \`root_dir\` for this.)
root_dir = "${buildConfig.root}"

# URL exclusions (regex patterns).
exclude = [
  # Development/preview URLs — no server running during link-check.
  "^https?://localhost(?::[0-9]+)?(?:/.*)?$",
  "^https?://127\\\\.0\\\\.0\\\\.1(?::[0-9]+)?(?:/.*)?$",
  # Template-literal placeholders in markdown code samples
  # (e.g. \${repo}, \${commit}, \${path}, percent-encoded variants).
  "\\\\$\\\\{[^}]*\\\\}",
  "%7B.*%7D",
  # Planned future repos (referenced in spec text but not yet created).
  "^https?://github\\\\.com/artagon/content(?:[/?#].*)?$",
  # Routes that ship with update-site-marketing-redesign / brand-assets
  # (not yet on production). Remove after those changes archive.
  "^https?://artagon\\\\.com/(writing|use-cases|standards|brand)(?:[/?#].*)?$",
  "^https?://artagon\\\\.com/og/(use-cases|standards|brand|writing)\\\\.png$",
  # i18n placeholder routes referenced in externalize-strings-and-add-i18n
  # proposal/spec/tasks. The /es/ subtree + /about page are documented
  # future surfaces; they don't 200 today and shouldn't block the gate.
  # Remove after the i18n change archives and the routes ship.
  "^https?://artagon\\\\.com/(about|es(?:/.*)?)$",
  # Webfont CDN root URLs — referenced as preconnect / DNS-prefetch
  # targets in BaseLayout.astro and DESIGN.md. The bare domains 404
  # (only specific paths like /css2?family=… serve), but the
  # preconnect hint and prose references are valid usage.
  "^https?://fonts\\\\.googleapis\\\\.com/?$",
  "^https?://fonts\\\\.gstatic\\\\.com/?$",
  "^https?://fonts\\\\.googleapis\\\\.com/css2\\\\?%E2%80%A6$",
  # CDN path-prefix referenced in scripts/csp.mjs allow-list (pt431).
  # The path-prefix \`/npm/@docsearch/\` is not a directory listing;
  # bare GET 400s. Specific bundle URLs (/npm/@docsearch/js@3.9.0)
  # are SRI-pinned and load fine.
  "^https?://cdn\\\\.jsdelivr\\\\.net/npm/@docsearch/?$",
  # Astro RSS docs URL moved during a recent docs reorg. The README
  # reference is informational; the actual RSS integration is wired
  # via @astrojs/rss in src/pages/writing/feed.xml.ts.
  "^https?://docs\\\\.astro\\\\.build/en/guides/integrations-guide/rss/?$",
  # USMR rolling tasks.md narrative occasionally references
  # relative paths in backticks that lychee resolves to bogus
  # file:// URLs (e.g. \`writing/feed.xml\`, \`ink/SKILL.md\`, \`url\`).
  # The narrative is documentation, not navigable links — exclude
  # the misresolved file:// forms targeted at the USMR change dir.
  "^file://.*/openspec/changes/update-site-marketing-redesign/(ink/SKILL\\\\.md|url|writing/feed\\\\.xml)$",
  # \`base = "."\` (above) resolves root-relative \`/writing/feed.xml\`
  # against the repo root, so it becomes a file:// path. The route
  # is built into \`.build/dist/writing/feed.xml\` at runtime but
  # doesn't exist in the source tree. Match the resolved file://
  # form so the gate doesn't flag a route that legitimately ships
  # only as a build artifact.
  "^file://.*/writing/feed\\\\.xml$",
  # Upstream link rot (acceptable; pinned reference is in archive.org).
  "^https?://playwright\\\\.dev/docs/test-patterns/?$",
  # AWS EC2 instance metadata service (IMDSv1) — referenced verbatim in
  # security review docs as the SSRF attack vector the cover-field regex
  # mitigates. Unreachable + non-routable from CI runners; do not probe.
  "^https?://169\\\\.254\\\\.169\\\\.254(?::[0-9]+)?(?:/.*)?$",
  # mailto and external services we shouldn't probe.
  "^mailto:",
  # Upstream new-design mock tree — referenced from AGENTS.md and PR notes
  # as the source of ported HTML/CSS, but intentionally not checked into
  # this repo (lives in a sibling working tree). Lychee resolves the
  # relative path to a file:// URL; exclude that target form.
  "^file://.*/new-design/",
  # Local Claude/agent skill references — \`.claude/skills\` is in
  # exclude_path for input-scanning, but doc references like
  # \`./.claude/skills/<name>\` still get checked as link targets. These
  # name user-level skills installed outside the repo (e.g.
  # review-verification-protocol); not all of them ship locally.
  "^file://.*/\\\\.claude/skills/",
  # W3C / upstream spec mirrors that are known-flaky from CI runners
  # (connection-reset on GitHub-hosted infrastructure). The spec text
  # is committed verbatim in openspec/.cache/design-md-spec.md and is
  # not a live dependency; exclude the upstream domain rather than
  # retrying indefinitely.
  "^https?://(www\\\\.)?designtokens\\\\.org/",
]
`;

// ---------- Run ----------
const results = [
  emitJson(join(ROOT, "lighthouserc.json"), lhci),
  emitToml(join(ROOT, "lychee.toml"), lycheeBody),
];

const wrote = results.filter((r) => r.changed);
if (CHECK_MODE && wrote.length > 0) {
  console.error(
    "✗ build config drift — run `npm run sync:build-config` locally and commit:",
  );
  for (const r of wrote) console.error(`  - ${r.path}`);
  exit(1);
}

for (const r of wrote) console.log(`✓ wrote ${r.path}`);
if (wrote.length === 0) console.log("✓ all generated files up-to-date");
